const provider = ($env.MEMORY_PROVIDER || 'n8n-static').toLowerCase();
const sessionId = $json.sessionId || 'default';
const userId = $json.userId || 'default';
const inputText = $json.inputText || '';
const responseText = $json.responseText || '';
const intent = $json.intent || '';

if (provider === 'sqlite') {
  const baseUrl = $env.SQLITE_MEMORY_URL || 'http://localhost:8710';
  await $helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/sessions',
    headers: { 'Content-Type': 'application/json' },
    body: {
      session_id: sessionId,
      user_id: userId,
      input: inputText,
      response: responseText,
      intent: intent,
      timestamp: Date.now()
    },
    timeout: 5000
  });
  return [{ json: { ...$json, saved: true } }];
}

const sd = $getWorkflowStaticData('global');
sd.sessions = sd.sessions || {};
sd.sessions[sessionId] = {
  userId,
  sessionId,
  lastMessage: inputText,
  lastResponse: responseText,
  lastIntent: intent,
  timestamp: new Date().toISOString(),
  version: '1.0.0'
};

const dataSize = JSON.stringify(sd).length;
if (dataSize > 800000) {
  const sessions = Object.entries(sd.sessions || {});
  sessions.sort((a, b) => (a[1].timestamp || 0) - (b[1].timestamp || 0));
  const toDelete = sessions.slice(0, Math.max(0, sessions.length - 100));
  toDelete.forEach(([key]) => delete sd.sessions[key]);
  console.log(JSON.stringify({ level: 'warn', timestamp: new Date().toISOString(), workflow: 'memory-adapter', message: 'Static data near limit — evicted old sessions', detail: { evicted: toDelete.length, remaining: Object.keys(sd.sessions || {}).length } }));
}

return [{ json: { ...$json, saved: true } }];

const { facts, sessionId, userId } = $json;
const provider = ($env.MEMORY_PROVIDER || 'n8n-static').toLowerCase();

if (provider === 'sqlite') {
  const baseUrl = $env.SQLITE_MEMORY_URL || 'http://localhost:8710';
  await $helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/facts',
    headers: { 'Content-Type': 'application/json' },
    body: { facts, user_id: userId || 'default' },
    timeout: 5000
  });
  return [{ json: { ...$json, factsSaved: facts ? facts.length : 0 } }];
}

const sd = $getWorkflowStaticData('global');
sd.facts = sd.facts || {};

for (const fact of (facts || [])) {
  const key = fact.category + ':' + fact.key;
  sd.facts[key] = { ...fact, userId, sessionId, updated: new Date().toISOString() };
}

const userFacts = Object.values(sd.facts).filter(f => f.userId === userId);
if (userFacts.length > 500) {
  userFacts.sort((a, b) => (a.updated || '').localeCompare(b.updated || ''));
  const toDelete = userFacts.slice(0, userFacts.length - 500);
  toDelete.forEach(f => {
    const fk = f.category + ':' + f.key;
    delete sd.facts[fk];
  });
  console.log(JSON.stringify({ level: 'warn', timestamp: new Date().toISOString(), workflow: 'memory-adapter', message: 'Per-user fact limit reached — evicted oldest facts', detail: { evicted: toDelete.length, userId } }));
}

return [{ json: { ...$json, factsSaved: facts ? facts.length : 0 } }];

const sessionId = $json.sessionId;
const provider = ($env.MEMORY_PROVIDER || 'n8n-static').toLowerCase();

if (provider === 'sqlite') {
  const baseUrl = $env.SQLITE_MEMORY_URL || 'http://localhost:8710';
  const response = await $helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/sessions/' + encodeURIComponent(sessionId),
    timeout: 5000
  });
  return [{ json: { ...$json, session: response.data.session || null } }];
}

const sd = $getWorkflowStaticData('global');
const session = sd.sessions?.[sessionId] || null;
return [{ json: { ...$json, session } }];

const { userId, category } = $json;
const provider = ($env.MEMORY_PROVIDER || 'n8n-static').toLowerCase();

if (provider === 'sqlite') {
  const baseUrl = $env.SQLITE_MEMORY_URL || 'http://localhost:8710';
  let url = baseUrl + '/facts?';
  const queryParams = [];
  if (userId) queryParams.push('user_id=' + encodeURIComponent(userId));
  if (category) queryParams.push('category=' + encodeURIComponent(category));
  url += queryParams.join('&');
  const response = await $helpers.httpRequest({ method: 'GET', url, timeout: 5000 });
  return [{ json: { ...$json, facts: response.data.facts || [] } }];
}

const sd = $getWorkflowStaticData('global');
const facts = sd.facts || {};
let result = Object.values(facts);
if (userId) result = result.filter(f => f.userId === userId);
if (category) result = result.filter(f => f.category === category);
return [{ json: { ...$json, facts: result } }];
